public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
    int earliest = 1, latest = 1;
    while ((firstPlayer + secondPlayer) != n + 1 || Math.abs(firstPlayer - secondPlayer) != 1) {
        if ((firstPlayer + secondPlayer) <= n + 1 && (firstPlayer - 1) / 2 == (secondPlayer - 1) / 2) break;
